// ============================================================================
// CONTRAST CHECKING UTILITIES
// ============================================================================

function getLuminance(hex) {
  const r = parseInt(hex.slice(1, 3), 16) / 255;
  const g = parseInt(hex.slice(3, 5), 16) / 255;
  const b = parseInt(hex.slice(5, 7), 16) / 255;
  const toLinear = (c) => (c <= 0.03928 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4));
  return 0.2126 * toLinear(r) + 0.7152 * toLinear(g) + 0.0722 * toLinear(b);
}

function getContrastRatio(hex1, hex2) {
  const l1 = getLuminance(hex1);
  const l2 = getLuminance(hex2);
  const lighter = Math.max(l1, l2);
  const darker = Math.min(l1, l2);
  return (lighter + 0.05) / (darker + 0.05);
}

// ============================================================================
// CIRCULAR QR COMPONENT
// ============================================================================

// Map color preset names to pre-generated QR SVG files
// Generated by circular_qr_batch.py with matching fg/bg colors


function CircularQR({ size = 120, qrColor = '#000000', bgColor = '#ffffff' }) {
  const coloredSvg = QR_SVG_RAW
    .replace(/fill="#000000"/g, 'fill="' + qrColor + '"')
    .replace(/stroke="#000000"/g, 'stroke="' + qrColor + '"')
    .replace(/fill="#ffffff"/g, 'fill="' + bgColor + '"');
  const dataUri = 'data:image/svg+xml;charset=utf-8,' + encodeURIComponent(coloredSvg);
  return (
    <g>
      <image
        href={dataUri}
        x={0} y={0}
        width={size} height={size}
      />
    </g>
  );
}

// ============================================================================
// HALO FRAME COMPONENT
// ============================================================================

function HaloFrame({ cx, cy, qrRadius, color = '#1a1a1a' }) {
  const rayCount = 62;
  const dotDistances = [1.198, 1.342, 1.486, 1.629, 1.773, 1.917];
  const dotRadii = [0.0549, 0.0477, 0.0406, 0.0335, 0.0263, 0.0192];
  const donutInnerR = qrRadius;
  const donutOuterR = qrRadius * 1.12;

  const dots = [];

  for (let ray = 0; ray < rayCount; ray++) {
    const angle = (ray / rayCount) * Math.PI * 2;
    const cos = Math.cos(angle);
    const sin = Math.sin(angle);

    // Generate 6 dots per ray
    for (let dotIdx = 0; dotIdx < dotDistances.length; dotIdx++) {
      const distance = qrRadius * dotDistances[dotIdx];
      const radius = qrRadius * dotRadii[dotIdx];
      dots.push({
        x: cx + distance * cos,
        y: cy + distance * sin,
        r: radius,
      });
    }
  }

  return (
    <g>
      {/* Donut ring (two concentric circles with fill-rule="evenodd") */}
      <path
        d={`M ${cx - donutOuterR} ${cy} A ${donutOuterR} ${donutOuterR} 0 1 1 ${cx + donutOuterR} ${cy} A ${donutOuterR} ${donutOuterR} 0 1 1 ${cx - donutOuterR} ${cy} Z M ${cx - donutInnerR} ${cy} A ${donutInnerR} ${donutInnerR} 0 1 0 ${cx + donutInnerR} ${cy} A ${donutInnerR} ${donutInnerR} 0 1 0 ${cx - donutInnerR} ${cy} Z`}
        fill={color}
        fillRule="evenodd"
      />

      {/* Halftone dots */}
      {dots.map((dot, i) => (
        <circle key={`halo-dot-${i}`} cx={dot.x} cy={dot.y} r={dot.r} fill={color} />
      ))}
    </g>
  );
}

// ============================================================================
// MAIN CUSTOMIZER COMPONENT
// ============================================================================

export default function QRCustomizerMockup() {
  const { user, signIn, signUp } = useAuth();
  const [authMode, setAuthMode] = useState('signin'); // 'signin' or 'signup'
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authError, setAuthError] = useState(null);
  const [authLoading, setAuthLoading] = useState(false);

  const [template, setTemplate] = useState('florida');
  const [qrSize, setQrSize] = useState(375);
  const [strokeWeight, setStrokeWeight] = useState(250); // 0-500%, 100 = default
  const [qrPosition, setQrPosition] = useState(STATE_TEMPLATES.florida.suggestedQR);
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [customColors, setCustomColors] = useState({ bg: '#ffffff', halo: '#000000', qr: '#000000', stateFill: '#2A9D8F', stateStroke: '#000000' });
  const [hasFill, setHasFill] = useState(false);
  const [hasStroke, setHasStroke] = useState(true);
  const [useGradient, setUseGradient] = useState(false);
  const [gradientColor2, setGradientColor2] = useState('#023e8a');
  const [gradientAngle, setGradientAngle] = useState(135); // degrees
  const [showFullPreview, setShowFullPreview] = useState(false);
  const svgRef = useRef(null);
  const [showOrderModal, setShowOrderModal] = useState(false);
  const [orderSubmitting, setOrderSubmitting] = useState(false);
  const [orderSuccess, setOrderSuccess] = useState(null); // { shortCode, qrUrl }
  const [orderError, setOrderError] = useState(null);
  const [shippingForm, setShippingForm] = useState({
    name: '', address: '', city: '', state: '', zip: '', email: '',
  });
  const [couponCode, setCouponCode] = useState('');
  const [savedProfile, setSavedProfile] = useState(null);
  const [useSavedAddress, setUseSavedAddress] = useState(false);

  const currentTemplate = STATE_TEMPLATES[template];
  const currentColors = customColors;

  // Handle template change and reset QR position
  const handleTemplateChange = (key) => {
    setTemplate(key);
    setQrPosition(STATE_TEMPLATES[key].suggestedQR);
  };

  // Handle drag start
  const handleMouseDown = (e) => {
    if (!svgRef.current) return;

    const svg = svgRef.current;
    const rect = svg.getBoundingClientRect();
    const svgX = e.clientX - rect.left;
    const svgY = e.clientY - rect.top;

    // Convert screen coords to SVG viewBox coords
    const viewBox = currentTemplate.viewBox.split(' ').map(Number);
    const [vx0, vy0, vWidth, vHeight] = viewBox;
    const scaleX = vWidth / rect.width;
    const scaleY = vHeight / rect.height;
    const vx = vx0 + svgX * scaleX;
    const vy = vy0 + svgY * scaleY;

    // Check if click is within QR circle
    const dist = Math.sqrt((vx - qrPosition.x) ** 2 + (vy - qrPosition.y) ** 2);
    if (dist < qrSize / 2 + 20) {
      setIsDragging(true);
      setDragOffset({ x: vx - qrPosition.x, y: vy - qrPosition.y });
    }
  };

  // Handle drag move
  const handleMouseMove = (e) => {
    if (!isDragging || !svgRef.current) return;

    const svg = svgRef.current;
    const rect = svg.getBoundingClientRect();
    const svgX = e.clientX - rect.left;
    const svgY = e.clientY - rect.top;

    const viewBox = currentTemplate.viewBox.split(' ').map(Number);
    const [vx0, vy0, vWidth, vHeight] = viewBox;
    const scaleX = vWidth / rect.width;
    const scaleY = vHeight / rect.height;
    const vx = vx0 + svgX * scaleX;
    const vy = vy0 + svgY * scaleY;

    setQrPosition({
      x: vx - dragOffset.x,
      y: vy - dragOffset.y,
    });
  };

  // Handle drag end
  const handleMouseUp = () => {
    setIsDragging(false);
  };

  // Touch support
  const handleTouchStart = (e) => {
    if (e.touches.length !== 1) return;
    const touch = e.touches[0];
    handleMouseDown({ clientX: touch.clientX, clientY: touch.clientY });
  };

  const handleTouchMove = (e) => {
    if (e.touches.length !== 1) return;
    e.preventDefault();
    const touch = e.touches[0];
    handleMouseMove({ clientX: touch.clientX, clientY: touch.clientY });
  };

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      window.addEventListener('touchmove', handleTouchMove, { passive: false });
      window.addEventListener('touchend', handleMouseUp);
      return () => {
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('mouseup', handleMouseUp);
        window.removeEventListener('touchmove', handleTouchMove);
        window.removeEventListener('touchend', handleMouseUp);
      };
    }
  }, [isDragging, dragOffset, qrPosition]);

  const handleReset = () => {
    setQrPosition(currentTemplate.suggestedQR);
  };

  // Capture the sticker SVG for order submission
  // - Strips drag hints and cursor styles
  // - Inlines QR SVG (replaces data-URI <image> with actual SVG elements for Illustrator compat)
  // - Fixes font references for print software
  const captureDesignSvg = () => {
    if (!svgRef.current) return null;
    try {
      const clone = svgRef.current.cloneNode(true);
      // Remove the "drag to move" hint text
      const hints = clone.querySelectorAll('[data-drag-hint]');
      hints.forEach((el) => el.remove());
      // Remove cursor styles (drag affordance)
      clone.style.cursor = 'default';

      // Inline any data-URI SVG <image> elements (QR code) for Illustrator compatibility
      const images = clone.querySelectorAll('image');
      images.forEach((img) => {
        const href = img.getAttribute('href') || img.getAttributeNS('http://www.w3.org/1999/xlink', 'href');
        if (href && href.startsWith('data:image/svg+xml')) {
          try {
            // Decode the SVG from the data URI
            const svgContent = decodeURIComponent(href.replace('data:image/svg+xml;charset=utf-8,', ''));
            const parser = new DOMParser();
            const doc = parser.parseFromString(svgContent, 'image/svg+xml');
            const innerSvg = doc.documentElement;

            // Create a positioned <svg> element to replace the <image>
            const replacement = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
            replacement.setAttribute('x', img.getAttribute('x') || '0');
            replacement.setAttribute('y', img.getAttribute('y') || '0');
            replacement.setAttribute('width', img.getAttribute('width'));
            replacement.setAttribute('height', img.getAttribute('height'));
            replacement.setAttribute('viewBox', innerSvg.getAttribute('viewBox'));
            replacement.setAttribute('overflow', 'visible');
            replacement.setAttribute('data-qr-element', 'true');

            // Copy all child elements from the decoded SVG
            while (innerSvg.firstChild) {
              replacement.appendChild(innerSvg.firstChild);
            }

            // Replace the <image> with the inlined SVG
            img.parentNode.replaceChild(replacement, img);
          } catch (e) {
            console.warn('Failed to inline SVG image:', e);
          }
        }
      });

      // Fix font references: replace CSS-only font stacks with concrete fonts
      const svgStr = clone.outerHTML
        .replace(/system-ui,\s*/g, '')
        .replace(/, system-ui/g, '');

      return svgStr;
    } catch (err) {
      console.error('SVG capture failed:', err);
      return null;
    }
  };

  // Build the sticker config object from current state
  const buildStickerConfig = () => ({
    state_template: template,
    qr_position_x: qrPosition.x,
    qr_position_y: qrPosition.y,
    qr_size: qrSize,
    color_bg: customColors.bg,
    color_stroke: hasStroke ? customColors.stateStroke : null,
    color_fill: hasFill ? customColors.stateFill : null,
    color_qr: customColors.qr,
    color_halo: customColors.halo,
    stroke_weight: strokeWeight,
    has_fill: hasFill,
    has_stroke: hasStroke,
    gradient_enabled: useGradient,
    gradient_color1: hasFill ? customColors.stateFill : null,
    gradient_color2: useGradient ? gradientColor2 : null,
    gradient_angle: gradientAngle,
  });

  // Submit the order to the backend
  const handleOrderSubmit = async () => {
    setOrderSubmitting(true);
    setOrderError(null);

    const designSvg = captureDesignSvg();
    if (!designSvg) {
      setOrderError('Could not capture sticker design. Please try again.');
      setOrderSubmitting(false);
      return;
    }

    try {
      const payload = JSON.stringify({
        sticker_config: buildStickerConfig(),
        design_svg: designSvg,
        // Free test for now — swap to 'square' or 'stripe' when payment is wired up
        payment_method: couponCode ? 'coupon' : 'free_test',
        payment_ref: couponCode || undefined,
        shipping: shippingForm.name ? {
          name: shippingForm.name,
          address: shippingForm.address,
          city: shippingForm.city,
          state: shippingForm.state,
          zip: shippingForm.zip,
        } : undefined,
      });
      const res = await fetch('/api/orders', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: payload,
      });

      const data = await res.json();

      if (!res.ok) {
        setOrderError(data.error || 'Order failed. Please try again.');
        setOrderSubmitting(false);
        return;
      }

      setOrderSuccess({
        shortCode: data.short_code,
        qrUrl: data.qr_url,
        orderId: data.order.id,
      });
      setOrderSubmitting(false);
    } catch (err) {
      console.error('Order submission error:', err);
      setOrderError('Network error. Please check your connection and try again.');
      setOrderSubmitting(false);
    }
  };

  const viewBox = currentTemplate.viewBox;

  // Render state shape based on template type
  // strokeScale is proportional to each state's coordinate space
  // strokeWeight slider: 0 = no stroke, 100 = default, 500 = 5x (boss mode)
  const baseStroke = currentTemplate.strokeScale || 20;
  const sw = baseStroke * (strokeWeight / 100);
  const thinSw = baseStroke * 0.15 * (strokeWeight / 100); // thin outline in fill mode

  // Fill and stroke controlled by toggles + color pickers
  // Gradient: convert angle (degrees) to SVG linearGradient x1/y1/x2/y2
  const gradAngleRad = (gradientAngle - 90) * (Math.PI / 180);
  const gx1 = 50 - 50 * Math.cos(gradAngleRad);
  const gy1 = 50 - 50 * Math.sin(gradAngleRad);
  const gx2 = 50 + 50 * Math.cos(gradAngleRad);
  const gy2 = 50 + 50 * Math.sin(gradAngleRad);

  const shouldUseGradient = useGradient && hasFill;
  const shapeFill = !hasFill ? 'none' : (shouldUseGradient ? 'url(#state-fill-gradient)' : currentColors.stateFill);
  const shapeStroke = !hasStroke ? 'none' : currentColors.stateStroke;
  const shapeStrokeWidth = !hasStroke ? 0 : sw;

  const renderStateShape = () => {
    if (template === 'florida') {
      return (
        <g>
          {/* Main outline */}
          <path
            d={FLORIDA_ELEMENTS_MAIN}
            fill={shapeFill}
            stroke={shapeStroke}
            strokeWidth={shapeStrokeWidth}
            strokeMiterlimit="10"
          />
          {/* Detail paths (islands, keys, coastal features) */}
          {FLORIDA_ELEMENTS_DETAILS.map((d, i) => (
            <path
              key={`detail-${i}`}
              d={d}
              fill={shapeFill}
              stroke={shapeStroke}
              strokeWidth={shapeStrokeWidth}
              strokeMiterlimit="10"
            />
          ))}
        </g>
      );
    }

    if (template === 'georgia') {
      return (
        <g>
          <path
            d={GEORGIA_MAIN_PATH}
            fill={shapeFill}
            stroke={shapeStroke}
            strokeWidth={shapeStrokeWidth}
            strokeMiterlimit="10"
          />
          <polygon
            points={GEORGIA_POLYGON_POINTS}
            fill={shapeFill}
            stroke={shapeStroke}
            strokeWidth={shapeStrokeWidth}
            strokeMiterlimit="10"
          />
        </g>
      );
    }

    // Texas - single path
    return (
      <path
        d={TEXAS_MAIN_PATH}
        fill={shapeFill}
        stroke={shapeStroke}
        strokeWidth={shapeStrokeWidth}
        strokeMiterlimit="10"
      />
    );
  };

  return (
    <div
      style={{
        fontFamily: "'Plus Jakarta Sans', -apple-system, BlinkMacSystemFont, sans-serif",
        backgroundColor: '#0a0f14',
        color: '#f1f5f9',
        minHeight: '100vh',
        padding: '16px',
        boxSizing: 'border-box',
        maxWidth: '900px',
        margin: '0 auto',
      }}
    >
      {/* Header */}
      <div style={{ marginBottom: '16px' }}>
        <a href="https://qrstkr.com" style={{ textDecoration: 'none' }}>
          <h1 style={{
            margin: '0 0 4px 0',
            fontSize: '24px',
            fontWeight: '700',
            background: 'linear-gradient(135deg, #f1f5f9, #5eead4)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            backgroundClip: 'text',
            cursor: 'pointer',
          }}>QRSTKR</h1>
        </a>
        <p style={{ margin: '0', fontSize: '14px', color: '#94a3b8' }}>Sticker Designer</p>
      </div>

      {/* Main Layout */}
      <div
        style={{
          display: 'flex',
          gap: '24px',
          flexWrap: 'wrap',
          justifyContent: 'center',
        }}
      >
        {/* Canvas Area */}
        <div style={{ flex: '1 1 auto', width: '100%', maxWidth: '480px', minWidth: '200px' }}>
          <div
            style={{
              backgroundColor: '#ffffff',
              border: '1px solid rgba(45, 212, 191, 0.15)',
              borderRadius: '12px',
              padding: '12px',
              maxHeight: '55vh',
              aspectRatio: '1 / 1',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            <svg
              ref={svgRef}
              viewBox={viewBox}
              style={{
                width: '100%',
                height: '100%',
                maxHeight: '100%',
                display: 'block',
                cursor: isDragging ? 'grabbing' : 'grab',
              }}
              onMouseDown={handleMouseDown}
              onTouchStart={handleTouchStart}
            >
              {/* Gradient definition for state fill */}
              {shouldUseGradient && (
                <defs>
                  <linearGradient id="state-fill-gradient" x1={`${gx1}%`} y1={`${gy1}%`} x2={`${gx2}%`} y2={`${gy2}%`}>
                    <stop offset="0%" stopColor={currentColors.stateFill} />
                    <stop offset="100%" stopColor={gradientColor2} />
                  </linearGradient>
                </defs>
              )}

              {/* Sticker background (uses theme bg color) */}
              <rect
                x={viewBox.split(' ')[0]}
                y={viewBox.split(' ')[1]}
                width={viewBox.split(' ')[2]}
                height={viewBox.split(' ')[3]}
                fill={currentColors.bg}
                rx="20"
                ry="20"
              />

              {/* State shape */}
              {renderStateShape()}

              {/* Halo frame and QR as a group - HALO ALWAYS ON */}
              <g>
                <HaloFrame
                  cx={qrPosition.x}
                  cy={qrPosition.y}
                  qrRadius={qrSize / 2}
                  color={currentColors.halo}
                />

                <svg
                  x={qrPosition.x - qrSize / 2}
                  y={qrPosition.y - qrSize / 2}
                  width={qrSize}
                  height={qrSize}
                  viewBox={`0 0 ${qrSize} ${qrSize}`}
                  style={{ overflow: 'visible' }}
                >
                  <CircularQR
                    size={qrSize}
                    qrColor={currentColors.qr}
                    bgColor={currentColors.bg}
                  />
                </svg>
              </g>

              {/* Drag hint */}
              <text
                data-drag-hint="true"
                x={qrPosition.x}
                y={qrPosition.y + qrSize / 2 + 30}
                textAnchor="middle"
                fontSize="14"
                fill="#64748b"
                style={{ pointerEvents: 'none' }}
              >
                drag to move
              </text>

              {/* Copyright */}
              <text
                x={viewBox.split(' ')[2] / 2}
                y={viewBox.split(' ')[3] - 12}
                textAnchor="middle"
                fontSize="16"
                fill="#94a3b8"
                fontFamily="'Plus Jakarta Sans', system-ui, sans-serif"
                style={{ pointerEvents: 'none' }}
              >
                QRSTKR.com © 2026
              </text>
            </svg>
          </div>
        </div>

        {/* Control Panel */}
        <div style={{ flex: '1 1 auto', width: '100%', maxWidth: '320px', minWidth: '280px' }}>
          {/* State Template Selector */}
          <div style={{ marginBottom: '24px' }}>
            <label style={{ display: 'block', fontSize: '12px', fontWeight: '600', marginBottom: '8px', textTransform: 'uppercase', letterSpacing: '0.05em', color: '#64748b' }}>
              State
            </label>
            <div style={{ display: 'flex', gap: '8px' }}>
              {Object.entries(STATE_TEMPLATES).map(([key, tmpl]) => (
                <button
                  key={key}
                  onClick={() => handleTemplateChange(key)}
                  style={{
                    flex: 1,
                    padding: '8px 12px',
                    backgroundColor: template === key ? '#1c252f' : '#1c252f',
                    color: template === key ? '#f1f5f9' : '#94a3b8',
                    background: template === key ? 'linear-gradient(135deg, #2dd4bf, #5eead4)' : 'transparent',
                    border: template === key ? 'none' : '1px solid rgba(45, 212, 191, 0.08)',
                    borderRadius: '8px',
                    cursor: 'pointer',
                    fontSize: '12px',
                    fontWeight: '600',
                    transition: 'all 0.2s',
                  }}
                >
                  {tmpl.name}
                </button>
              ))}
            </div>
          </div>

          {/* Colors */}
          <div style={{ marginBottom: '24px' }}>
            <label style={{ display: 'block', fontSize: '12px', fontWeight: '600', marginBottom: '8px', textTransform: 'uppercase', letterSpacing: '0.05em', color: '#64748b' }}>
              Colors
            </label>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: '6px', marginBottom: '12px' }}>
              <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px', minWidth: 0 }}>
                <input type="color" value={customColors.bg} onChange={(e) => setCustomColors({ ...customColors, bg: e.target.value })} style={{ width: '100%', height: '44px', border: '1px solid rgba(45, 212, 191, 0.15)', borderRadius: '8px', cursor: 'pointer', backgroundColor: '#0f1419', padding: '2px' }} />
                <label style={{ fontSize: '9px', fontWeight: '600', color: '#64748b', textTransform: 'uppercase', textAlign: 'center', letterSpacing: '0.03em' }}>BG</label>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px', minWidth: 0 }}>
                {hasStroke ? (
                  <div style={{ position: 'relative', width: '100%', height: '44px' }}>
                    <input type="color" value={customColors.stateStroke} onChange={(e) => setCustomColors({ ...customColors, stateStroke: e.target.value })} style={{ width: '100%', height: '44px', border: '1px solid rgba(45, 212, 191, 0.15)', borderRadius: '8px', cursor: 'pointer', backgroundColor: '#0f1419', padding: '2px' }} />
                    <div onClick={() => setHasStroke(false)} style={{ position: 'absolute', top: '-4px', right: '-4px', width: '14px', height: '14px', borderRadius: '50%', backgroundColor: '#ef4444', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '9px', color: '#fff', fontWeight: 'bold', lineHeight: 1, border: '1px solid #0f1419' }}>×</div>
                  </div>
                ) : (
                  <div onClick={() => setHasStroke(true)} style={{ width: '100%', height: '44px', border: '1px solid rgba(45, 212, 191, 0.15)', borderRadius: '8px', cursor: 'pointer', backgroundColor: '#0f1419', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden' }}>
                    <svg width="28" height="28" viewBox="0 0 28 28"><rect x="2" y="2" width="24" height="24" rx="4" fill="none" stroke="#475569" strokeWidth="1.5"/><line x1="4" y1="24" x2="24" y2="4" stroke="#ef4444" strokeWidth="2.5" strokeLinecap="round"/></svg>
                  </div>
                )}
                <label style={{ fontSize: '9px', fontWeight: '600', color: hasStroke ? '#64748b' : '#ef4444', textTransform: 'uppercase', textAlign: 'center', letterSpacing: '0.03em' }}>Stroke</label>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px', minWidth: 0 }}>
                {hasFill ? (
                  <div style={{ position: 'relative', width: '100%', height: '44px' }}>
                    <input type="color" value={customColors.stateFill} onChange={(e) => setCustomColors({ ...customColors, stateFill: e.target.value })} style={{ width: '100%', height: '44px', border: '1px solid rgba(45, 212, 191, 0.15)', borderRadius: '8px', cursor: 'pointer', backgroundColor: '#0f1419', padding: '2px' }} />
                    <div onClick={() => setHasFill(false)} style={{ position: 'absolute', top: '-4px', right: '-4px', width: '14px', height: '14px', borderRadius: '50%', backgroundColor: '#ef4444', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '9px', color: '#fff', fontWeight: 'bold', lineHeight: 1, border: '1px solid #0f1419' }}>×</div>
                  </div>
                ) : (
                  <div onClick={() => setHasFill(true)} style={{ width: '100%', height: '44px', border: '1px solid rgba(45, 212, 191, 0.15)', borderRadius: '8px', cursor: 'pointer', backgroundColor: '#0f1419', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden' }}>
                    <svg width="28" height="28" viewBox="0 0 28 28"><rect x="2" y="2" width="24" height="24" rx="4" fill="none" stroke="#475569" strokeWidth="1.5"/><line x1="4" y1="24" x2="24" y2="4" stroke="#ef4444" strokeWidth="2.5" strokeLinecap="round"/></svg>
                  </div>
                )}
                <label style={{ fontSize: '9px', fontWeight: '600', color: hasFill ? '#64748b' : '#ef4444', textTransform: 'uppercase', textAlign: 'center', letterSpacing: '0.03em' }}>Fill</label>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px', minWidth: 0 }}>
                <input type="color" value={customColors.halo} onChange={(e) => setCustomColors({ ...customColors, halo: e.target.value })} style={{ width: '100%', height: '44px', border: '1px solid rgba(45, 212, 191, 0.15)', borderRadius: '8px', cursor: 'pointer', backgroundColor: '#0f1419', padding: '2px' }} />
                <label style={{ fontSize: '9px', fontWeight: '600', color: '#64748b', textTransform: 'uppercase', textAlign: 'center', letterSpacing: '0.03em' }}>Halo</label>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '4px', minWidth: 0 }}>
                <input type="color" value={customColors.qr} onChange={(e) => setCustomColors({ ...customColors, qr: e.target.value })} style={{ width: '100%', height: '44px', border: '1px solid rgba(45, 212, 191, 0.15)', borderRadius: '8px', cursor: 'pointer', backgroundColor: '#0f1419', padding: '2px' }} />
                <label style={{ fontSize: '9px', fontWeight: '600', color: '#64748b', textTransform: 'uppercase', textAlign: 'center', letterSpacing: '0.03em' }}>QR</label>
              </div>
            </div>

            {/* Gradient Fill Controls */}
            {hasFill && (
            <div style={{
              padding: '12px',
              backgroundColor: '#0f1419',
              border: '1px solid rgba(45, 212, 191, 0.08)',
              borderRadius: '12px',
              marginBottom: '12px',
            }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: useGradient ? '10px' : '0' }}>
                <label style={{ fontSize: '11px', fontWeight: '600', color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                  Gradient Fill
                </label>
                <button
                  onClick={() => setUseGradient(!useGradient)}
                  style={{
                    width: '40px',
                    height: '22px',
                    borderRadius: '11px',
                    border: 'none',
                    backgroundColor: useGradient ? '#2dd4bf' : '#334155',
                    cursor: 'pointer',
                    position: 'relative',
                    transition: 'background-color 0.2s',
                  }}
                >
                  <div style={{
                    width: '16px',
                    height: '16px',
                    borderRadius: '50%',
                    backgroundColor: '#fff',
                    position: 'absolute',
                    top: '3px',
                    left: useGradient ? '21px' : '3px',
                    transition: 'left 0.2s',
                  }} />
                </button>
              </div>
              {useGradient && (
                <div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '6px', flex: 1 }}>
                      <input
                        type="color"
                        value={currentColors.stateFill}
                        onChange={(e) => {
                          setCustomColors({ ...customColors, stateFill: e.target.value });
                        }}
                        style={{ width: '36px', height: '28px', border: '1px solid rgba(45, 212, 191, 0.15)', borderRadius: '6px', cursor: 'pointer', backgroundColor: '#0f1419', padding: '1px' }}
                      />
                      <span style={{ fontSize: '10px', color: '#64748b' }}>→</span>
                      <input
                        type="color"
                        value={gradientColor2}
                        onChange={(e) => setGradientColor2(e.target.value)}
                        style={{ width: '36px', height: '28px', border: '1px solid rgba(45, 212, 191, 0.15)', borderRadius: '6px', cursor: 'pointer', backgroundColor: '#0f1419', padding: '1px' }}
                      />
                    </div>
                    <div style={{
                      width: '48px',
                      height: '28px',
                      borderRadius: '6px',
                      background: `linear-gradient(${gradientAngle}deg, ${currentColors.stateFill}, ${gradientColor2})`,
                      border: '1px solid rgba(45, 212, 191, 0.15)',
                    }} />
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <label style={{ fontSize: '9px', fontWeight: '600', color: '#64748b', textTransform: 'uppercase', whiteSpace: 'nowrap' }}>Angle</label>
                    <input
                      type="range"
                      min="0"
                      max="360"
                      value={gradientAngle}
                      onChange={(e) => setGradientAngle(parseInt(e.target.value))}
                      style={{ flex: 1, accentColor: '#2dd4bf' }}
                    />
                    <span style={{ fontSize: '11px', color: '#94a3b8', minWidth: '32px', textAlign: 'right' }}>{gradientAngle}°</span>
                  </div>
                </div>
              )}
            </div>
            )}

            {/* Contrast Indicator */}
            {(() => {
              const qrContrast = getContrastRatio(currentColors.qr, currentColors.bg);
              const isGoodQR = qrContrast >= 4.5;
              return (
                <div style={{ marginTop: '12px' }}>
                  <div
                    style={{
                      padding: '10px 12px',
                      backgroundColor: isGoodQR ? 'rgba(74, 222, 128, 0.1)' : 'rgba(251, 191, 36, 0.1)',
                      border: isGoodQR ? '1px solid rgba(74, 222, 128, 0.2)' : '1px solid rgba(251, 191, 36, 0.2)',
                      borderRadius: '8px',
                      fontSize: '11px',
                      color: isGoodQR ? '#4ade80' : '#fbbf24',
                      marginBottom: '8px',
                    }}
                  >
                    <strong>QR ↔ BG:</strong> {qrContrast.toFixed(1)}:1 {isGoodQR ? '✓ Scannable' : '⚠️ QR may not scan'}
                  </div>
                  <div
                    style={{
                      padding: '10px 12px',
                      backgroundColor: '#0f1419',
                      border: '1px solid rgba(45, 212, 191, 0.08)',
                      borderRadius: '8px',
                      fontSize: '11px',
                      color: '#64748b',
                      marginTop: '8px',
                    }}
                  >
                    QR code preview is approximate — final colors applied at generation
                  </div>
                </div>
              );
            })()}
          </div>

          {/* Stroke Weight Slider */}
          {hasStroke && (
          <div style={{ marginBottom: '24px' }}>
            <label style={{ display: 'flex', justifyContent: 'space-between', fontSize: '12px', fontWeight: '600', marginBottom: '8px', textTransform: 'uppercase', letterSpacing: '0.05em', color: '#64748b' }}>
              <span>Stroke Weight</span>
              <span>{strokeWeight === 0 ? 'None' : `${strokeWeight}%`}</span>
            </label>
            <input
              type="range"
              min="0"
              max="500"
              step="10"
              value={strokeWeight}
              onChange={(e) => setStrokeWeight(Number(e.target.value))}
              style={{
                width: '100%',
                cursor: 'pointer',
              }}
            />
          </div>
          )}

          {/* QR Size Slider */}
          <div style={{ marginBottom: '24px' }}>
            <label style={{ display: 'flex', justifyContent: 'space-between', fontSize: '12px', fontWeight: '600', marginBottom: '8px', textTransform: 'uppercase', letterSpacing: '0.05em', color: '#64748b' }}>
              <span>QR Code Size</span>
              <span>{qrSize}</span>
            </label>
            <input
              type="range"
              min="250"
              max="500"
              value={qrSize}
              onChange={(e) => setQrSize(Number(e.target.value))}
              style={{
                width: '100%',
                cursor: 'pointer',
              }}
            />
          </div>

          {/* Action Buttons */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginBottom: '8px' }}>
            <button
              onClick={handleReset}
              style={{
                padding: '12px',
                backgroundColor: '#1c252f',
                color: '#f1f5f9',
                border: '1px solid rgba(45, 212, 191, 0.15)',
                borderRadius: '12px',
                cursor: 'pointer',
                fontSize: '12px',
                fontWeight: '600',
                transition: 'all 0.2s',
              }}
              onMouseEnter={(e) => {
                e.target.style.borderColor = '#2dd4bf';
                e.target.style.backgroundColor = '#151c24';
              }}
              onMouseLeave={(e) => {
                e.target.style.borderColor = 'rgba(45, 212, 191, 0.15)';
                e.target.style.backgroundColor = '#1c252f';
              }}
            >
              Reset Position
            </button>
            <button
              onClick={() => setShowFullPreview(true)}
              style={{
                padding: '12px',
                background: 'linear-gradient(135deg, #2dd4bf, #5eead4)',
                color: '#0a0f14',
                border: 'none',
                borderRadius: '12px',
                cursor: 'pointer',
                fontSize: '12px',
                fontWeight: '600',
                boxShadow: '0 4px 20px rgba(45, 212, 191, 0.15)',
                transition: 'all 0.2s',
              }}
              onMouseEnter={(e) => (e.target.style.opacity = '0.9')}
              onMouseLeave={(e) => (e.target.style.opacity = '1')}
            >
              Preview Full Design
            </button>
          </div>

          {/* Order Button */}
          <button
            onClick={async () => {
              setShowOrderModal(true);
              setOrderSuccess(null);
              setOrderError(null);
              // Fetch saved profile for address prefill
              if (user) {
                try {
                  const res = await fetch('/api/profile');
                  if (res.ok) {
                    const data = await res.json();
                    const p = data.profile;
                    if (p && p.shipping_name) {
                      setSavedProfile(p);
                      // Auto-prefill if shipping form is empty
                      if (!shippingForm.name && !shippingForm.address) {
                        setUseSavedAddress(true);
                        setShippingForm({
                          name: p.shipping_name || '',
                          address: p.shipping_address || '',
                          city: p.shipping_city || '',
                          state: p.shipping_state || '',
                          zip: p.shipping_zip || '',
                          email: '',
                        });
                      }
                    }
                  }
                } catch (e) {
                  console.warn('Could not load saved profile:', e);
                }
              }
            }}
            style={{
              width: '100%',
              padding: '14px',
              background: 'linear-gradient(135deg, #f59e0b, #f97316)',
              color: '#0a0f14',
              border: 'none',
              borderRadius: '12px',
              cursor: 'pointer',
              fontSize: '14px',
              fontWeight: '700',
              letterSpacing: '0.5px',
              boxShadow: '0 4px 20px rgba(245, 158, 11, 0.25)',
              transition: 'all 0.2s',
              marginBottom: '24px',
            }}
            onMouseEnter={(e) => (e.target.style.opacity = '0.9')}
            onMouseLeave={(e) => (e.target.style.opacity = '1')}
          >
            Order This Sticker
          </button>

          {/* Info Note */}
          <div
            style={{
              padding: '12px',
              backgroundColor: '#0f1419',
              border: '1px solid rgba(45, 212, 191, 0.08)',
              borderRadius: '8px',
              fontSize: '11px',
              lineHeight: '1.6',
              color: '#64748b',
            }}
          >
            QR codes generated by circular_qr_batch.py. Halo always ON (composited from Halftone Urchin). Stroke/Fill rendering for state outlines. Square sticker format with white background.
          </div>
        </div>
      </div>

      {/* Fullscreen Preview Modal */}
      {showFullPreview && (
        <div
          onClick={() => setShowFullPreview(false)}
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            width: '100vw',
            height: '100vh',
            backgroundColor: 'rgba(0, 0, 0, 0.92)',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 9999,
            padding: '24px',
            cursor: 'pointer',
          }}
        >
          <div style={{
            width: '100%',
            maxWidth: '500px',
            maxHeight: '80vh',
            aspectRatio: '1 / 1',
            backgroundColor: '#ffffff',
            borderRadius: '16px',
            padding: '12px',
            boxShadow: '0 20px 60px rgba(0, 0, 0, 0.5)',
          }}>
            <svg
              viewBox={viewBox}
              style={{ width: '100%', height: '100%', display: 'block' }}
            >
              {shouldUseGradient && (
                <defs>
                  <linearGradient id="state-fill-gradient" x1={`${gx1}%`} y1={`${gy1}%`} x2={`${gx2}%`} y2={`${gy2}%`}>
                    <stop offset="0%" stopColor={currentColors.stateFill} />
                    <stop offset="100%" stopColor={gradientColor2} />
                  </linearGradient>
                </defs>
              )}
              <rect
                x={viewBox.split(' ')[0]}
                y={viewBox.split(' ')[1]}
                width={viewBox.split(' ')[2]}
                height={viewBox.split(' ')[3]}
                fill={currentColors.bg}
                rx="20"
                ry="20"
              />
              {renderStateShape()}
              <g>
                <HaloFrame
                  cx={qrPosition.x}
                  cy={qrPosition.y}
                  qrRadius={qrSize / 2}
                  color={currentColors.halo}
                />
                <svg
                  x={qrPosition.x - qrSize / 2}
                  y={qrPosition.y - qrSize / 2}
                  width={qrSize}
                  height={qrSize}
                  viewBox="0 0 49 49"
                >
                  <CircularQR
                    size={49}
                    qrColor={currentColors.qr}
                    bgColor={currentColors.bg}
                  />
                </svg>
              </g>
              {/* Copyright */}
              <text
                x={viewBox.split(' ')[2] / 2}
                y={viewBox.split(' ')[3] - 12}
                textAnchor="middle"
                fontSize="16"
                fill="#94a3b8"
                fontFamily="'Plus Jakarta Sans', system-ui, sans-serif"
                style={{ pointerEvents: 'none' }}
              >
                QRSTKR.com © 2026
              </text>
            </svg>
          </div>
          <p style={{ color: '#64748b', fontSize: '13px', marginTop: '16px' }}>Tap anywhere to close</p>
        </div>
      )}

      {/* Order Modal */}
      {showOrderModal && (
        <div
          onClick={(e) => {
            if (e.target === e.currentTarget && !orderSubmitting) {
              setShowOrderModal(false);
            }
          }}
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            width: '100vw',
            height: '100vh',
            backgroundColor: 'rgba(0, 0, 0, 0.85)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 10000,
            padding: '24px',
          }}
        >
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              width: '100%',
              maxWidth: '480px',
              maxHeight: '90vh',
              overflowY: 'auto',
              backgroundColor: '#0f1419',
              border: '1px solid rgba(245, 158, 11, 0.2)',
              borderRadius: '16px',
              padding: '32px',
            }}
          >
            {/* Success State */}
            {orderSuccess ? (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '48px', marginBottom: '16px' }}>&#10003;</div>
                <h2 style={{ color: '#2dd4bf', fontSize: '22px', marginBottom: '8px' }}>Order Placed!</h2>
                <p style={{ color: '#94a3b8', fontSize: '14px', lineHeight: '1.6', marginBottom: '16px' }}>
                  Your sticker is in the queue. We&apos;ll print it and ship it your way.
                </p>
                <div style={{
                  backgroundColor: '#1c252f',
                  borderRadius: '8px',
                  padding: '16px',
                  marginBottom: '24px',
                  textAlign: 'left',
                }}>
                  <p style={{ color: '#64748b', fontSize: '12px', margin: '0 0 4px 0' }}>Order ID</p>
                  <p style={{ color: '#f1f5f9', fontSize: '13px', fontFamily: 'monospace', margin: '0 0 12px 0' }}>
                    {orderSuccess.orderId}
                  </p>
                  <p style={{ color: '#64748b', fontSize: '12px', margin: '0 0 4px 0' }}>Sticker Code</p>
                  <p style={{ color: '#f59e0b', fontSize: '16px', fontWeight: '700', fontFamily: 'monospace', margin: '0 0 12px 0' }}>
                    {orderSuccess.shortCode}
                  </p>
                  <p style={{ color: '#64748b', fontSize: '12px', margin: '0 0 4px 0' }}>QR URL</p>
                  <p style={{ color: '#2dd4bf', fontSize: '13px', fontFamily: 'monospace', margin: 0 }}>
                    {orderSuccess.qrUrl}
                  </p>
                </div>
                <button
                  onClick={() => {
                    setShowOrderModal(false);
                    setOrderSuccess(null);
                  }}
                  style={{
                    padding: '12px 32px',
                    background: 'linear-gradient(135deg, #2dd4bf, #5eead4)',
                    color: '#0a0f14',
                    border: 'none',
                    borderRadius: '12px',
                    cursor: 'pointer',
                    fontSize: '14px',
                    fontWeight: '700',
                  }}
                >
                  Done
                </button>
              </div>
            ) : (
              /* Order Form */
              <>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
                  <h2 style={{ color: '#f1f5f9', fontSize: '20px', fontWeight: '700', margin: 0 }}>
                    Order Your Sticker
                  </h2>
                  <button
                    onClick={() => !orderSubmitting && setShowOrderModal(false)}
                    style={{
                      background: 'none',
                      border: 'none',
                      color: '#64748b',
                      fontSize: '24px',
                      cursor: orderSubmitting ? 'not-allowed' : 'pointer',
                      padding: '0 4px',
                    }}
                  >
                    &times;
                  </button>
                </div>

                {/* Auth Gate — show sign-in/up if not logged in */}
                {!user ? (
                  <div>
                    <div style={{
                      backgroundColor: '#1c252f',
                      borderRadius: '8px',
                      padding: '20px',
                      marginBottom: '20px',
                      textAlign: 'center',
                    }}>
                      <p style={{ color: '#f1f5f9', fontSize: '15px', fontWeight: '600', marginBottom: '4px' }}>
                        {authMode === 'signin' ? 'Sign in to place your order' : 'Create an account to order'}
                      </p>
                      <p style={{ color: '#64748b', fontSize: '12px', margin: 0 }}>
                        Your design is saved — just need an account to check out.
                      </p>
                    </div>

                    {authError && (
                      <div style={{
                        backgroundColor: 'rgba(239, 68, 68, 0.1)',
                        border: '1px solid rgba(239, 68, 68, 0.3)',
                        borderRadius: '8px',
                        padding: '12px',
                        marginBottom: '16px',
                        color: '#ef4444',
                        fontSize: '13px',
                      }}>
                        {authError}
                      </div>
                    )}

                    <div style={{ marginBottom: '10px' }}>
                      <label style={{ color: '#64748b', fontSize: '11px', display: 'block', marginBottom: '4px' }}>Email</label>
                      <input
                        type="email"
                        value={authEmail}
                        onChange={(e) => setAuthEmail(e.target.value)}
                        placeholder="you@email.com"
                        disabled={authLoading}
                        style={{
                          width: '100%',
                          padding: '10px 12px',
                          backgroundColor: '#1c252f',
                          color: '#f1f5f9',
                          border: '1px solid rgba(45, 212, 191, 0.15)',
                          borderRadius: '8px',
                          fontSize: '13px',
                          outline: 'none',
                          boxSizing: 'border-box',
                        }}
                      />
                    </div>
                    <div style={{ marginBottom: '16px' }}>
                      <label style={{ color: '#64748b', fontSize: '11px', display: 'block', marginBottom: '4px' }}>Password</label>
                      <input
                        type="password"
                        value={authPassword}
                        onChange={(e) => setAuthPassword(e.target.value)}
                        placeholder={authMode === 'signup' ? 'Create a password' : 'Your password'}
                        disabled={authLoading}
                        style={{
                          width: '100%',
                          padding: '10px 12px',
                          backgroundColor: '#1c252f',
                          color: '#f1f5f9',
                          border: '1px solid rgba(45, 212, 191, 0.15)',
                          borderRadius: '8px',
                          fontSize: '13px',
                          outline: 'none',
                          boxSizing: 'border-box',
                        }}
                      />
                    </div>

                    <button
                      onClick={async () => {
                        setAuthLoading(true);
                        setAuthError(null);
                        const result = authMode === 'signin'
                          ? await signIn(authEmail, authPassword)
                          : await signUp(authEmail, authPassword);
                        if (result.error) {
                          setAuthError(result.error);
                        }
                        setAuthLoading(false);
                      }}
                      disabled={authLoading || !authEmail || !authPassword}
                      style={{
                        width: '100%',
                        padding: '14px',
                        background: authLoading ? '#374151' : 'linear-gradient(135deg, #f59e0b, #f97316)',
                        color: authLoading ? '#9ca3af' : '#0a0f14',
                        border: 'none',
                        borderRadius: '12px',
                        cursor: authLoading ? 'not-allowed' : 'pointer',
                        fontSize: '15px',
                        fontWeight: '700',
                        marginBottom: '16px',
                      }}
                    >
                      {authLoading ? 'Working...' : (authMode === 'signin' ? 'Sign In' : 'Create Account')}
                    </button>

                    <p style={{ textAlign: 'center', fontSize: '13px', color: '#64748b', margin: 0 }}>
                      {authMode === 'signin' ? (
                        <>No account? <button onClick={() => { setAuthMode('signup'); setAuthError(null); }} style={{ background: 'none', border: 'none', color: '#2dd4bf', cursor: 'pointer', fontSize: '13px', fontWeight: '600' }}>Sign up</button></>
                      ) : (
                        <>Already have one? <button onClick={() => { setAuthMode('signin'); setAuthError(null); }} style={{ background: 'none', border: 'none', color: '#2dd4bf', cursor: 'pointer', fontSize: '13px', fontWeight: '600' }}>Sign in</button></>
                      )}
                    </p>
                  </div>
                ) : (
                  <>
                {/* Sticker Summary */}
                <div style={{
                  backgroundColor: '#1c252f',
                  borderRadius: '8px',
                  padding: '12px',
                  marginBottom: '20px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '12px',
                }}>
                  <div style={{
                    width: '60px',
                    height: '60px',
                    borderRadius: '8px',
                    overflow: 'hidden',
                    backgroundColor: customColors.bg,
                    flexShrink: 0,
                  }}>
                    <svg viewBox={viewBox} style={{ width: '100%', height: '100%' }}>
                      <rect
                        x={viewBox.split(' ')[0]}
                        y={viewBox.split(' ')[1]}
                        width={viewBox.split(' ')[2]}
                        height={viewBox.split(' ')[3]}
                        fill={customColors.bg}
                      />
                      {renderStateShape()}
                    </svg>
                  </div>
                  <div>
                    <p style={{ color: '#f1f5f9', fontSize: '14px', fontWeight: '600', margin: '0 0 4px 0' }}>
                      {currentTemplate.name} Sticker
                    </p>
                    <p style={{ color: '#64748b', fontSize: '12px', margin: 0 }}>
                      Custom QR Code &bull; 2&quot; vinyl
                    </p>
                  </div>
                </div>

                {/* Shipping Info */}
                <div style={{ marginBottom: '20px' }}>
                  <h3 style={{ color: '#94a3b8', fontSize: '13px', fontWeight: '600', marginBottom: '12px', textTransform: 'uppercase', letterSpacing: '0.5px' }}>
                    Shipping
                  </h3>
                  {savedProfile && savedProfile.shipping_name && (
                    <label style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '14px', cursor: 'pointer', color: '#94a3b8', fontSize: '13px' }}>
                      <input
                        type="checkbox"
                        checked={useSavedAddress}
                        onChange={(e) => {
                          const checked = e.target.checked;
                          setUseSavedAddress(checked);
                          if (checked) {
                            setShippingForm({
                              name: savedProfile.shipping_name || '',
                              address: savedProfile.shipping_address || '',
                              city: savedProfile.shipping_city || '',
                              state: savedProfile.shipping_state || '',
                              zip: savedProfile.shipping_zip || '',
                              email: '',
                            });
                          } else {
                            setShippingForm({ name: '', address: '', city: '', state: '', zip: '', email: '' });
                          }
                        }}
                        style={{ accentColor: '#2dd4bf' }}
                      />
                      Use my saved address
                    </label>
                  )}
                  {[
                    { key: 'name', label: 'Full Name', placeholder: 'Jane Doe' },
                    { key: 'address', label: 'Address', placeholder: '123 Main St' },
                    { key: 'city', label: 'City', placeholder: 'Miami' },
                  ].map(({ key, label, placeholder }) => (
                    <div key={key} style={{ marginBottom: '10px' }}>
                      <label style={{ color: '#64748b', fontSize: '11px', display: 'block', marginBottom: '4px' }}>{label}</label>
                      <input
                        type="text"
                        value={shippingForm[key]}
                        onChange={(e) => setShippingForm((f) => ({ ...f, [key]: e.target.value }))}
                        placeholder={placeholder}
                        disabled={orderSubmitting}
                        style={{
                          width: '100%',
                          padding: '10px 12px',
                          backgroundColor: '#1c252f',
                          color: '#f1f5f9',
                          border: '1px solid rgba(45, 212, 191, 0.15)',
                          borderRadius: '8px',
                          fontSize: '13px',
                          outline: 'none',
                          boxSizing: 'border-box',
                        }}
                      />
                    </div>
                  ))}
                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                    <div>
                      <label style={{ color: '#64748b', fontSize: '11px', display: 'block', marginBottom: '4px' }}>State</label>
                      <input
                        type="text"
                        value={shippingForm.state}
                        onChange={(e) => setShippingForm((f) => ({ ...f, state: e.target.value }))}
                        placeholder="FL"
                        disabled={orderSubmitting}
                        style={{
                          width: '100%',
                          padding: '10px 12px',
                          backgroundColor: '#1c252f',
                          color: '#f1f5f9',
                          border: '1px solid rgba(45, 212, 191, 0.15)',
                          borderRadius: '8px',
                          fontSize: '13px',
                          outline: 'none',
                          boxSizing: 'border-box',
                        }}
                      />
                    </div>
                    <div>
                      <label style={{ color: '#64748b', fontSize: '11px', display: 'block', marginBottom: '4px' }}>ZIP</label>
                      <input
                        type="text"
                        value={shippingForm.zip}
                        onChange={(e) => setShippingForm((f) => ({ ...f, zip: e.target.value }))}
                        placeholder="33101"
                        disabled={orderSubmitting}
                        style={{
                          width: '100%',
                          padding: '10px 12px',
                          backgroundColor: '#1c252f',
                          color: '#f1f5f9',
                          border: '1px solid rgba(45, 212, 191, 0.15)',
                          borderRadius: '8px',
                          fontSize: '13px',
                          outline: 'none',
                          boxSizing: 'border-box',
                        }}
                      />
                    </div>
                  </div>
                </div>

                {/* Coupon Code */}
                <div style={{ marginBottom: '20px' }}>
                  <h3 style={{ color: '#94a3b8', fontSize: '13px', fontWeight: '600', marginBottom: '12px', textTransform: 'uppercase', letterSpacing: '0.5px' }}>
                    Coupon Code (optional)
                  </h3>
                  <input
                    type="text"
                    value={couponCode}
                    onChange={(e) => setCouponCode(e.target.value.toUpperCase())}
                    placeholder="e.g. TESTBETA"
                    disabled={orderSubmitting}
                    style={{
                      width: '100%',
                      padding: '10px 12px',
                      backgroundColor: '#1c252f',
                      color: '#f59e0b',
                      border: '1px solid rgba(245, 158, 11, 0.2)',
                      borderRadius: '8px',
                      fontSize: '13px',
                      fontFamily: 'monospace',
                      fontWeight: '600',
                      letterSpacing: '1px',
                      outline: 'none',
                      boxSizing: 'border-box',
                    }}
                  />
                </div>

                {/* Error Message */}
                {orderError && (
                  <div style={{
                    backgroundColor: 'rgba(239, 68, 68, 0.1)',
                    border: '1px solid rgba(239, 68, 68, 0.3)',
                    borderRadius: '8px',
                    padding: '12px',
                    marginBottom: '16px',
                    color: '#ef4444',
                    fontSize: '13px',
                  }}>
                    {orderError}
                  </div>
                )}

                {/* Price Note */}
                <div style={{
                  backgroundColor: '#1c252f',
                  borderRadius: '8px',
                  padding: '12px',
                  marginBottom: '20px',
                  textAlign: 'center',
                }}>
                  <p style={{ color: '#64748b', fontSize: '12px', margin: '0 0 4px 0' }}>
                    {couponCode ? 'Coupon will be applied at checkout' : 'Beta testing — orders are free'}
                  </p>
                  <p style={{ color: '#f59e0b', fontSize: '20px', fontWeight: '700', margin: 0 }}>
                    {couponCode ? 'Coupon Applied' : '$0.00'}
                  </p>
                </div>

                {/* Submit */}
                <button
                  onClick={handleOrderSubmit}
                  disabled={orderSubmitting}
                  style={{
                    width: '100%',
                    padding: '14px',
                    background: orderSubmitting
                      ? '#374151'
                      : 'linear-gradient(135deg, #f59e0b, #f97316)',
                    color: orderSubmitting ? '#9ca3af' : '#0a0f14',
                    border: 'none',
                    borderRadius: '12px',
                    cursor: orderSubmitting ? 'not-allowed' : 'pointer',
                    fontSize: '15px',
                    fontWeight: '700',
                    letterSpacing: '0.5px',
                    transition: 'all 0.2s',
                  }}
                >
                  {orderSubmitting ? 'Placing Order...' : 'Place Order'}
                </button>
                  </>
                )}
              </>
            )}
          </div>
        </div>
      )}

      {/* Footer */}
      <footer style={{
        borderTop: '1px solid rgba(45, 212, 191, 0.08)',
        paddingTop: '16px',
        marginTop: '24px',
        textAlign: 'center',
      }}>
        <p style={{ margin: 0, fontSize: '12px', color: '#64748b' }}>
          <a href="https://qrstkr.com" style={{ color: '#94a3b8', textDecoration: 'none' }}>QRSTKR</a> &bull; A Hydraulics SR-80 project &bull; &copy; 2026
        </p>
      </footer>
    </div>
  );
}
